Symbols are new primitive built-in object types introduced as part of ES6.
Symbols are often used to add unique property keys to an object that won't collide with keys any other code might add to the object, 
and which are hidden from any mechanisms other code will typically use to access the object.

const sym1 = Symbol();
const sym = new Symbol(); // TypeError
const sym2 = Symbol("foo");
const sym3 = Symbol("foo");
console.log(sym2 == sym3) // false
console.log(typeof sym2); // symbol

//---- use cases of Symbols -----
const user = { name: "John Doe" };
const secretId = Symbol('secret-id');

// Add a property using a Symbol key
user[secretId] = '12345';

console.log(user.name); // "John Doe"
console.log(user[secretId]); // "12345"

// The symbol property is ignored by standard enumeration
for (const key in user) {
  console.log(key); // Only logs "name"
}

//---- Can be used to create Enum like properties -----
const CarState = Object.freeze({
  DRIVE: Symbol('drive'),
  IDLE: Symbol('idle'),
});

function changeCarState(car, newState) {
  if (newState === CarState.DRIVE) {
    console.log('Wroom, wroom!');
    car.state = newState;
  } else if (newState === CarState.IDLE) {
    console.log('Waiting for ya!');
    car.state = newState;
  }
}

const employee = {
    name: "John Doe",
    age: 30,
    position: "Software Engineer",
}

-- Here we are creating a new object "newEmp" that inherits from "employee"
-- The newEmp object will have access to all properties of the employee object through the prototype chain
let newEmp = Object.create(employee);
newEmp.gender = "Male";

console.log(newEmp); -- Output: {gender: "Male"}, it only shows the own properties of newEmp
console.log(newEmp.name); -- Output: {name: "John Doe"}, it accesses the name property through the prototype chain

-- newEmp.[[Prototype]] has properties gender.
-- newEmp.[[Prototype]].[[Prototype]] is Object.prototype.
-- Finally, newEmp.[[Prototype]].[[Prototype]].[[Prototype]] is null.
-- This is the end of the prototype chain, as by definition null has no [[Prototype]].
-- Thus, the full prototype chain looks like:
-- { gender: "Male" } ---> { name: "John Doe", age: 30, position: "Software Engineer" } ---> Object.prototype ---> null

-- Both of the following lines will show the prototype of newEmp, which is the employee object
console.log(newEmp.__proto__);
console.log(Object.getPrototypeOf(newEmp));

const obj = {
    a: 1,
    b: 2,
    c: 3
}

const newObj = Object.create(obj);
newObj.c = 4;
console.log(newObj.c); //O/P will be 4, 

// As "c" is the own property of newObj and prototype(obj) also has a "c" property, but it is not visited.
// This is called Property Shadowing

let arr = [1,2,3,4];
console.log(arr.sum()); // TypeError: arr.sum is not a function

// Getting error because there is no default function named sum().
// We can add a function directly in prototype of Array().
Array.prototype.sum = function() {
    return this.reduce((acc, red) => {
        return acc+red;
    }, 0);
}
console.log(arr.sum()); // 10

// No, not everything is an object in JavaScript. Many things like(strings, numbers, Booleans) are primitives, not objects.
// Unlike objects, primitive values are immutable.

let temp = "Hello World";
temp.c = "Test"; // Wont throw any compile/runtime error
console.log(temp); // Hello World
console.log(temp.c); // undefined, because temp is a primitive value and not an object, so it cannot have properties

// But if we uses constructor classes to create any primitive data then it will behave like Object:
let temp1 = new String("Hello World"); // In this case temp1 will be of type Object.
temp1.c = "Test";
console.log(temp1); // [String: "Hello World"] { c: "Test" }, because temp1 is an object created using the String constructor, so it can have properties.
console.log(temp1.valueOf()); // Hello World, because temp1 is an object created using the String constructor, valueOf method will return the primitive string value.
console.log(temp1.c); // Test, because temp1 is an object created using the String constructor, so it can have properties.
console.log(typeof temp1); // object, because temp1 is an object created using the String constructor, so its type is object
