// However Functions are fully-fledged objects, and inherit from Object (actually Object.prototype).
// Functions therefore can do anything objects can, including having properties.

// The optional chaining operator provides a way to safely access nested object properties, 
//   array elements, or call functions that might not exist.

// If at any point in the chain a reference is null or undefined, 
//   the expression short-circuits and returns undefined instead of throwing a TypeError.

const user = {
  name: 'Ana',
  contact: {
    email: 'ana@mail.com'
  }
};
const email = user.contact?.email; // "ana@mail.com"
const phone = user.details?.phone; // undefined (prevents error if 'details' is missing)
user.contact.onConnect?.(); // Calls the function if it exists, otherwise does nothing

// The nullish coalescing operator is a logical operator that provides a default value 
//   when the left-hand operand is specifically null or undefined.
// It is an improvement over the logical OR (||) operator because it treats falsy values 
//   like 0, false, or "" (empty string) as valid, not triggering the default value.

const count = 0;
const text = "";

const qty = count || 42;         // qty is 42 (because 0 is falsy)
const message = text || "hi!";   // message is "hi!" (because "" is falsy)

const safeQty = count ?? 42;     // safeQty is 0 (because 0 is not nullish)
const safeMessage = text ?? "hi!"; // safeMessage is "" (because "" is not nullish)

/**
 * getters and setters are special methods(known as accessor properties) that provide controlled access to object data, 
 * allowing us to execute logic when a property is retrieved or modified
 */
let person = {
    firstName: 'Aston',
    lastName: 'Martin',
    score: 754,
    /**
     * Computed Properties: Getters can dynamically calculate a value based on other properties, 
     * so the value is always up-to-date.
     * 
     * Read-Only/Write-Only Properties: By defining a getter without a setter, we can create a read-only property.
     * Here fullName is readOnly property
     */
    get fullName() {
        return `${this.firstName} ${this.lastName}`;
    },
    /**
     * Data Validation: Setters can enforce rules and validation logic before a value is stored, ensuring data integrity.
     * Here age is writeOnly property
     */
    set age(num) {
        if(num<1) return; 
        age = num;
    },
    /**
     * Encapsulation: They hide the internal implementation details of properties, allowing us to manage data access.
     */
    get isEligibleForAdmission() {
        if(this.score < 750) return false;
        return true;
    }
}

console.log(person.fullName); //Aston Martin
person.fullName = 'Test Name';
console.log(person.fullName); //Aston Martin
person.age = 34;
console.log(person.age); //undefined(WriteOnly Property)
console.log(person.isEligibleForAdmission); //true

class Account {
  #balance = 0; // Truly private field (ES2022 syntax)

  set _creditAmount(amount) {
    if(amount > this.#balance) {
      console.log('Insufficient Amount');
      return;
    }
    this.#balance -= amount;
  }

  // Setter with validation
  set _depositAmount(amount) {
    if (amount < 0) {
      console.log("Balance cannot be negative!");
    } else {
      this.#balance += amount;
    }
  }
}

const acc = new Account();
acc._depositAmount(500);
acc._creditAmount(100); // Setter is used (validation runs)
acc._depositAmount(-50); // Output: Balance cannot be negative! (validation prevents bad data)

