/**
 * A closure is a function that has access to its own scope, the outer function's scope, and the global scope.
 * It allows the inner function to access variables from the outer function even after the outer function has finished executing.
 * 
 * In this example, the `makeCounter` function creates a closure that retains access to the `count` variable, 
 * allowing the returned function to increment and return the count value each time it is called.
 * This demonstrates how closures enable functions to maintain state and access variables from their enclosing scope, 
 * making them powerful tools for creating private variables and functions in JavaScript.
 * 
 * A closure is the combination of a function bundled together(enclosed) with references to its surrounding state(the lexical environment).
 */
function makeCounter() {
    let count = 0;
    return function() {
        count++;
        return count;
    };
}

const counter = makeCounter(); // Create a new counter instance
console.log(counter()); // Output: 1, the count variable is accessed and incremented
console.log(counter()); // Output: 2, the count variable retains its value between calls
console.log(counter()); // Output: 3, the count variable continues to be updated and accessed through the closure
